import React, { useState, useEffect, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { Toast } from 'primereact/toast';
import axios from 'axios';
import { BASE_URL } from '../../helpers/BaseUrl';
import { Dropdown } from 'primereact/dropdown';
import Error from '../../components/Error';
import { Panel } from 'primereact/panel';

export default function Debtor() {

    const statuses = [{"id": 0, "status": true, "name": "Si"}, {"id": 1, "status": false, "name": "No"}];
    const toast = useRef(null);
    let today = new Date();

    const [course, setCourse] = useState(null);
    const [year, setYear] = useState(today.getFullYear());
    const [month, setMonth] = useState(today.getMonth());
    const [languajes, setLanguajes] = useState(null);
    const [languaje, setLanguaje] = useState(null);
    const [courses, setCourses] = useState(null);
    const [chargingCourse, setChargingCourse] = useState(false);
    const [showError, setShowError] = useState(false);
    const [filteringData, setFilteringData] = useState(false);
    const [years, setYears] = useState(null);
    const [months, setMonths] = useState(null);
    const [invoices, setInvoices] = useState(null);
    const [status, setStatus] = useState(true);
    const [filtering, setFiltering] = useState(false); // eslint-disable-line no-unused-vars

    const font = { fontFamily: "'Inter', 'Segoe UI', sans-serif" };
    const labelStyle = { fontSize: '0.82rem', fontWeight: 600, color: '#495057', marginBottom: 4, ...font };

    useEffect(() => {
        async function loadLanguajes() {
            try {
                await axios.get(`${BASE_URL}/api/years`).then(({ data: { data: years } }) => {
                    setYears(years);
                });
                await axios.get(`${BASE_URL}/api/months`).then(({ data: { data: months } }) => {
                    months.splice(12, 1);
                    setMonths(months);
                });
                await axios.get(`${BASE_URL}/api/languajes?all=1`).then(({ data: { data: { data: languajes } } }) => {
                    setLanguajes(languajes);
                    setCourses(null);
                    setFilteringData(false);
                });
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de idiomas');
                setShowError(true);
            }
        }
        loadLanguajes();
    }, []);

    useEffect(() => {
        async function loadCourses() {
            try {
                if (languaje != null) {
                    setChargingCourse(true);
                    setCourses(null);
                    await axios.get(`${BASE_URL}/api/languajes/${languaje}/courses?all=1`).then(({ data: { data: { data: courses } } }) => {
                        setCourses(courses);
                        setChargingCourse(false);
                        setFilteringData(false);
                    });
                }
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de cursos');
                setShowError(true);
                setChargingCourse(false);
            }
        }
        loadCourses();
    }, [languaje]);

    useEffect(() => {
        async function getInvoicesByFilter() {
            try {
                setFiltering(true);
                if (languaje === null || year === null || month === null) {
                    return;
                }
                if (languaje !== null || year !== null || month !== null || status !== null) {
                    setFilteringData(true);
                }
                await axios.get(`${BASE_URL}/api/debtors?languaje=${languaje}&curso=${course}&year=${year}&month=${month}&status=${status}`).then(data => {
                    setInvoices(data.data.data);
                    setFiltering(false);
                    setFilteringData(false);
                }).catch((error) => {
                    console.log(error);
                    console.warn('Hubo un problema con la carga de los deudores');
                    setShowError(true);
                    setFiltering(false);
                    setFilteringData(false);
                });
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de los deudores');
                setShowError(true);
                setFiltering(false);
                setFilteringData(false);
            }
        }
        getInvoicesByFilter();
    }, [languaje, year, month, course, status]);

    const studentBody = (rowData) => (
        <span style={{ fontWeight: 600, color: '#1a3320', ...font }}>{rowData.student}</span>
    );

    const amountOwedBody = (rowData) => (
        <span style={{
            background: '#ffebee', color: '#c62828', borderRadius: 6,
            padding: '2px 10px', fontWeight: 700, fontSize: '0.85rem', ...font
        }}>
            $ {rowData.amountOwed}
        </span>
    );

    const monthFeeBody = (rowData) => (
        <span style={{ color: '#495057', fontWeight: 500, ...font }}>$ {rowData.monthFee}</span>
    );

    const monthsOwedBody = (rowData) => (
        <span style={{
            background: rowData.monthsOwed >= 3 ? '#ffebee' : '#fff3e0',
            color: rowData.monthsOwed >= 3 ? '#c62828' : '#e65100',
            borderRadius: 12, padding: '2px 10px', fontWeight: 700, fontSize: '0.8rem', ...font
        }}>
            {rowData.monthsOwed}
        </span>
    );

    const lastDateBody = (rowData) => {
        if (!rowData.lastDatePaid) return <span style={{ color: '#9e9e9e', ...font }}>—</span>;
        const parts = rowData.lastDatePaid.split('-');
        if (parts.length === 3) {
            return <span style={{ color: '#495057', ...font }}>{parts[2]}/{parts[1]}/{parts[0]}</span>;
        }
        return <span style={{ color: '#495057', ...font }}>{rowData.lastDatePaid}</span>;
    };

    const panelHeaderTemplate = (options, title, count) => {
        return (
            <div
                className="p-d-flex p-ai-center"
                style={{
                    gap: '0.6rem', cursor: 'pointer', padding: '0.6rem 1rem',
                    background: 'linear-gradient(135deg, #f8fdf8 0%, #e8f5e9 100%)',
                    borderRadius: '8px 8px 0 0',
                }}
                onClick={options.onTogglerClick}
            >
                <i className={options.collapsed ? 'pi pi-chevron-right' : 'pi pi-chevron-down'}
                    style={{ color: '#3ab54a', fontSize: '0.85rem', transition: 'transform 0.2s' }} />
                <span style={{ fontWeight: 700, color: '#1a3320', fontSize: '0.95rem', ...font }}>{title}</span>
                {count !== undefined && (
                    <span style={{
                        background: '#e8f5e9', color: '#2e7d32', borderRadius: 12,
                        padding: '1px 10px', fontSize: '0.75rem', fontWeight: 700,
                        border: '1px solid #a5d6a7', ...font
                    }}>
                        {count}
                    </span>
                )}
            </div>
        );
    };

    if (showError) {
        return (
            <Error mensaje={'Hubo un problema al cargar los registros de los de deudores'}></Error>
        );
    }

    return (
        <div className="p-grid crud-demo">
            <div className="p-col-12">
                <div className="p-d-flex p-ai-center p-mb-3" style={{ gap: '1rem' }}>
                    <div style={{
                        width: 48, height: 48, borderRadius: 12, flexShrink: 0,
                        background: 'linear-gradient(135deg, #3ab54a, #1a5c25)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        boxShadow: '0 4px 14px rgba(58,181,74,0.35)'
                    }}>
                        <i className="pi pi-money-bill" style={{ color: '#fff', fontSize: '1.4rem' }}></i>
                    </div>
                    <div>
                        <h2 className="p-m-0" style={{ color: '#1a3320', fontWeight: 800, fontSize: '1.45rem', lineHeight: 1.2, ...font }}>
                            Deudores
                        </h2>
                        <p className="p-m-0" style={{ color: '#6c757d', fontSize: '0.875rem', ...font }}>
                            Consulta de deudas por idioma, nivel y curso
                        </p>
                    </div>
                </div>

                <div className="card" style={{ borderRadius: 12, boxShadow: '0 2px 16px rgba(0,0,0,0.07)', border: 'none' }}>
                    <Toast ref={toast} />

                    {/* Filters */}
                    <div style={{
                        background: '#f8fdf8', borderRadius: 10, padding: '1rem 1.2rem',
                        border: '1px solid #e0e0e0', marginBottom: '1.2rem'
                    }}>
                        <div className="p-d-flex p-ai-center p-mb-3" style={{ gap: '0.5rem' }}>
                            <i className="pi pi-filter" style={{ color: '#3ab54a', fontSize: '0.9rem' }} />
                            <span style={{ fontWeight: 700, color: '#1a3320', fontSize: '0.9rem', ...font }}>Filtros</span>
                        </div>
                        <div className="p-fluid p-formgrid p-grid">
                            <div className="p-field p-col-12 p-md-2">
                                <label htmlFor="year" style={labelStyle}>Año</label>
                                <Dropdown
                                    appendTo={document.body} id="year" value={year}
                                    onChange={e => setYear(() => e.target.value !== undefined ? e.target.value : null)}
                                    options={years} optionValue="name" optionLabel="name"
                                    filter showClear filterBy="name" placeholder="-- Seleccione año --"
                                    style={{ borderRadius: 8, ...font, fontSize: '0.88rem' }}
                                />
                            </div>
                            <div className="p-field p-col-12 p-md-2">
                                <label htmlFor="month" style={labelStyle}>Mes</label>
                                <Dropdown
                                    appendTo={document.body} id="month" value={month}
                                    onChange={e => setMonth(() => e.target.value !== undefined ? e.target.value : null)}
                                    options={months} optionValue="id" optionLabel="id"
                                    filter showClear filterBy="id" placeholder="-- Seleccione mes --"
                                    style={{ borderRadius: 8, ...font, fontSize: '0.88rem' }}
                                />
                            </div>
                            <div className="p-field p-col-12 p-md-3">
                                <label htmlFor="languaje" style={labelStyle}>Idioma</label>
                                <Dropdown
                                    appendTo={document.body} id="languaje" value={languaje}
                                    onChange={e => setLanguaje(() => e.target.value !== undefined ? e.target.value : null)}
                                    options={languajes} optionLabel="name" optionValue="id"
                                    filter showClear filterBy="name" placeholder="-- Seleccione idioma --"
                                    style={{ borderRadius: 8, ...font, fontSize: '0.88rem' }}
                                />
                            </div>
                            <div className="p-field p-col-12 p-md-3">
                                <label htmlFor="course" style={labelStyle}>Curso</label>
                                <div style={{ position: 'relative' }}>
                                    <Dropdown
                                        appendTo={document.body} id="course" value={course}
                                        onChange={e => setCourse(() => e.target.value !== undefined ? e.target.value : null)}
                                        options={courses} optionLabel="nameId" optionValue="id"
                                        filter showClear filterBy="nameId"
                                        disabled={chargingCourse}
                                        placeholder={chargingCourse ? '' : '-- Seleccione curso --'}
                                        style={{ borderRadius: 8, ...font, fontSize: '0.88rem' }}
                                    />
                                    {chargingCourse && (
                                        <div style={{
                                            position: 'absolute', left: 0, top: 0, right: 0, bottom: 0,
                                            display: 'flex', alignItems: 'center', justifyContent: 'center', pointerEvents: 'none'
                                        }}>
                                            <i className="pi pi-spin pi-spinner" style={{ color: '#3ab54a', fontSize: '1.1rem', marginRight: 6 }} />
                                            <span style={{ color: '#6c757d', fontSize: '0.82rem', fontWeight: 500, ...font }}>Cargando cursos...</span>
                                        </div>
                                    )}
                                </div>
                            </div>
                            <div className="p-field p-col-12 p-md-2">
                                <label htmlFor="status" style={labelStyle}>Alumnos activos</label>
                                <Dropdown
                                    appendTo={document.body} id="status" value={status}
                                    onChange={e => setStatus(() => e.target.value !== undefined ? e.target.value : null)}
                                    options={statuses} optionLabel="name" optionValue="status"
                                    placeholder="-- Seleccione --"
                                    style={{ borderRadius: 8, ...font, fontSize: '0.88rem' }}
                                />
                            </div>
                        </div>
                    </div>

                    {/* Loading */}
                    {filteringData && (
                        <div className="p-d-flex p-ai-center p-jc-center p-py-4">
                            <i className="pi pi-spin pi-spinner" style={{ color: '#3ab54a', fontSize: '1.5rem', marginRight: 8 }} />
                            <span style={{ color: '#6c757d', fontSize: '0.9rem', fontWeight: 500, ...font }}>Cargando datos...</span>
                        </div>
                    )}

                    {/* Results */}
                    {!filteringData && invoices &&
                        invoices.map((invoiceLevel, id) => {
                            const keysLevel = Object.keys(invoiceLevel);
                            return (
                                <div key={id} style={{ marginBottom: '0.75rem' }}>
                                    {keysLevel.map((keyLevel, idLevel) => {
                                        const invoiceCourses = invoiceLevel[keyLevel];
                                        return (
                                            <Panel
                                                key={idLevel}
                                                headerTemplate={(opts) => panelHeaderTemplate(opts, keyLevel)}
                                                toggleable
                                                style={{ marginBottom: '0.5rem', border: '1px solid #e0e0e0', borderRadius: 10, overflow: 'hidden' }}
                                            >
                                                {invoiceCourses.map((invoiceCourse, idCurso) => {
                                                    const keyCourses = Object.keys(invoiceCourse);
                                                    return (
                                                        <div key={idCurso}>
                                                            {keyCourses.map((keyCourse, idInvoice) => {
                                                                var invoicess = [...invoiceCourse[keyCourse]];
                                                                var amountOwedTotal = invoicess[invoicess.length - 1];
                                                                invoicess.splice(invoicess.length - 1, 1);
                                                                return (
                                                                    <Panel
                                                                        key={idInvoice}
                                                                        headerTemplate={(opts) => panelHeaderTemplate(opts, keyCourse, invoicess.length + ' alumno(s)')}
                                                                        toggleable
                                                                        style={{
                                                                            marginBottom: '0.5rem', border: '1px solid #e8e8e8',
                                                                            borderRadius: 8, overflow: 'hidden'
                                                                        }}
                                                                    >
                                                                        <DataTable
                                                                            value={invoicess}
                                                                            className="datatable-responsive datatable-compact"
                                                                            rowHover stripedRows
                                                                            style={{ ...font, fontSize: '0.88rem' }}
                                                                        >
                                                                            <Column field="id" header="ID" style={{ width: '4rem' }} />
                                                                            <Column field="student" header="Alumno" body={studentBody} sortable />
                                                                            <Column field="lastDatePaid" header="Último pago" body={lastDateBody} />
                                                                            <Column field="lastMonthPaid" header="Último mes pagado" />
                                                                            <Column field="monthsOwed" header="Meses adeudados" body={monthsOwedBody} style={{ textAlign: 'center' }} />
                                                                            <Column field="monthFee" header="Cuota mensual" body={monthFeeBody} />
                                                                            <Column field="amountOwed" header="Monto adeudado" body={amountOwedBody} />
                                                                        </DataTable>
                                                                        {amountOwedTotal && amountOwedTotal.amountOwedTotal !== undefined && (
                                                                            <div className="p-d-flex p-ai-center p-jc-end" style={{
                                                                                padding: '0.75rem 1rem', marginTop: '0.5rem',
                                                                                background: 'linear-gradient(135deg, #fff8e1 0%, #fffde7 100%)',
                                                                                borderRadius: 8, border: '1px solid #ffe082'
                                                                            }}>
                                                                                <span style={{ fontWeight: 600, color: '#5d4037', fontSize: '0.9rem', marginRight: 8, ...font }}>
                                                                                    Total adeudado:
                                                                                </span>
                                                                                <span style={{
                                                                                    fontWeight: 800, color: '#c62828', fontSize: '1.1rem',
                                                                                    background: '#ffebee', borderRadius: 8, padding: '4px 14px',
                                                                                    border: '1px solid #ef9a9a', ...font
                                                                                }}>
                                                                                    $ {amountOwedTotal.amountOwedTotal}
                                                                                </span>
                                                                            </div>
                                                                        )}
                                                                    </Panel>
                                                                );
                                                            })}
                                                        </div>
                                                    );
                                                })}
                                            </Panel>
                                        );
                                    })}
                                </div>
                            );
                        })
                    }

                    {/* Empty state */}
                    {!filteringData && invoices && invoices.length === 0 && (
                        <div className="p-d-flex p-ai-center p-jc-center p-py-5" style={{ flexDirection: 'column', gap: '0.5rem' }}>
                            <i className="pi pi-check-circle" style={{ color: '#a5d6a7', fontSize: '2.5rem' }} />
                            <span style={{ color: '#6c757d', fontSize: '0.95rem', fontWeight: 500, ...font }}>
                                No se encontraron deudores con los filtros seleccionados.
                            </span>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}
